from urllib.parse import urlencode, urlparse, parse_qs

def build_login_redirect(login_url: str, current_url: str, redirect_param: str = "next") -> str:
    parsed_login = urlparse(login_url)
    existing_query = parse_qs(parsed_login.query, keep_blank_values=True)
    existing_query[redirect_param] = [current_url]
    new_query = urlencode(existing_query, doseq=True)
    return parsed_login._replace(query=new_query).geturl()

def get_post_login_destination(default_url: str, requested_redirect: str | None, allowed_hosts: set[str] | None = None) -> str:
    if not requested_redirect:
        return default_url

    parsed = urlparse(requested_redirect)

    if parsed.scheme or parsed.netloc:
        if not allowed_hosts or parsed.netloc not in allowed_hosts:
            return default_url

    return requested_redirect

def login_redirect_response(is_authenticated: bool, login_url: str, current_url: str) -> dict:
    if is_authenticated:
        return {"redirect": current_url}
    return {"redirect": build_login_redirect(login_url, current_url)}